SELECT ?language ?languageLabel WHERE {
  ?language wdt:P31 wd:Q7262 ;
           p:P1082 ?statement .
  ?statement ps:P1082 ?num .
  ?statement pq:P1107 ?proportion .
  FILTER(?proportion > 0.035)
  ?language rdfs:label ?languageLabel .
  FILTER(LANG(?languageLabel) = 'en')
}

